const item = $input.first().json || {};
const staticData = $getWorkflowStaticData('global');

function htmlEscape(text) {
  return String(text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function truncateRaw(text, max) {
  var value = String(text || '');
  return value.length <= max ? value : value.slice(0, max - 1) + '\u2026';
}

if (item.error || (typeof item === 'object' && item.error)) {
  var apiErrMsg = item.error?.message || 'n8n API unreachable';
  var apiErrorHash = String(apiErrMsg).slice(0, 300);
  var lastApiErrorHash = staticData.lastApiErrorHash || '';
  var lastApiErrorAt = staticData.lastApiErrorAt || 0;
  var now0 = Date.now();
  var shouldAlertApiError = apiErrorHash !== lastApiErrorHash || (now0 - lastApiErrorAt) > 3600000;
  if (shouldAlertApiError) {
    staticData.lastApiErrorHash = apiErrorHash;
    staticData.lastApiErrorAt = now0;
  }
  staticData.orphanUncertainty = { timestamp: new Date().toISOString(), reason: apiErrMsg };
  return [{
    json: {
      orphanState: 'api_error',
      apiError: true,
      hasOrphans: false,
      hasAlertableOrphans: false,
      shouldAlertOrphans: shouldAlertApiError,
      orphanCount: 0,
      alertableOrphanCount: 0,
      orphanArray: '[]',
      orphanAlertText: shouldAlertApiError
        ? '\u{1F534} <b>HEARTBEAT \u2014 API UNREACHABLE</b>\n\nn8n API at localhost:5678 is not responding.\nOrphan detection may be incomplete this cycle.\n\n<b>Error:</b> <code>' + htmlEscape(truncateRaw(apiErrMsg, 300)) + '</code>\n<b>Timestamp:</b> ' + new Date().toLocaleString('en-PH', { timeZone: 'Asia/Manila', year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false })
        : '',
      errorMessage: apiErrMsg
    }
  }];
}

var data = item.data || item;
var arr = Array.isArray(data) ? data : (Array.isArray(data.data) ? data.data : []);

if (!Array.isArray(arr)) {
  staticData.orphanUncertainty = { timestamp: new Date().toISOString(), reason: 'Unexpected n8n API response shape' };
  return [{
    json: {
      orphanState: 'api_error',
      apiError: true,
      hasOrphans: false,
      hasAlertableOrphans: false,
      shouldAlertOrphans: false,
      orphanCount: 0,
      alertableOrphanCount: 0,
      orphanArray: '[]',
      orphanAlertText: '',
      errorMessage: 'Unexpected API response shape'
    }
  }];
}

var healthData = (function() { try { return $('System Status').first().json || {}; } catch(e) { return {}; } })();

if (arr.length === 0) {
  var isActiveSystem = healthData.circuit_status === 'open' || healthData.circuit_status === 'half_open' || !!healthData.error;
  if (isActiveSystem) {
    staticData.orphanUncertainty = { timestamp: new Date().toISOString(), reason: 'API returned 0 running during active system' };
    return [{ json: { orphanState: 'uncertain', apiError: false, hasOrphans: false, hasAlertableOrphans: false, shouldAlertOrphans: false, orphanCount: 0, alertableOrphanCount: 0, orphanArray: '[]', orphanAlertText: '' } }];
  }
  delete staticData.orphanUncertainty;
  return [{ json: { orphanState: 'none', apiError: false, hasOrphans: false, hasAlertableOrphans: false, shouldAlertOrphans: false, orphanCount: 0, alertableOrphanCount: 0, orphanArray: '[]', orphanAlertText: '' } }];
}

var now = Date.now();
var threshold = 30 * 60 * 1000;
var MONITORING_WORKFLOW_IDS = [
  $env.SUPERVISOR_WORKFLOW_ID || '',
  $env.HEARTBEAT_WORKFLOW_ID || '',
  $env.RETENTION_WORKFLOW_ID || ''
].filter(Boolean).map(String);

var LONG_RUNNING_IDS = String($env.LONG_RUNNING_WORKFLOW_IDS || '').split(',').map(function(s) { return s.trim(); }).filter(Boolean);
var excludeIds = new Set([].concat(MONITORING_WORKFLOW_IDS, LONG_RUNNING_IDS));

var baseUrl = $env.N8N_BASE_URL || 'http://localhost:5678';

var orphans = arr.filter(function(exec) {
  var startedAtRaw = exec.startedAt || exec.createdAt;
  var startedAt = new Date(startedAtRaw).getTime();
  if (!startedAt || Number.isNaN(startedAt)) return false;
  return (now - startedAt) > threshold && !excludeIds.has(String(exec.workflowId));
}).map(function(exec) {
  return {
    executionId: String(exec.id),
    workflowId: String(exec.workflowId || 'unknown'),
    workflowName: exec.workflowName || exec.workflow?.name || 'unknown',
    startedAt: exec.startedAt || exec.createdAt,
    runningMinutes: Math.round((now - new Date(exec.startedAt || exec.createdAt).getTime()) / 60000),
    executionUrl: baseUrl + '/executions/' + String(exec.id)
  };
});

var orphanAlertKey = 'orphan_alert_memory';
var orphanMemory = staticData[orphanAlertKey] || {};
var ORPHAN_REALERT_MS = 60 * 60 * 1000;

var alertableOrphans = orphans.filter(function(o) {
  var last = orphanMemory[o.executionId] || 0;
  return (now - last) > ORPHAN_REALERT_MS;
});

for (var ao of alertableOrphans) { orphanMemory[ao.executionId] = now; }
for (var eid of Object.keys(orphanMemory)) {
  if (now - orphanMemory[eid] > 24 * 60 * 60 * 1000) delete orphanMemory[eid];
}
staticData[orphanAlertKey] = orphanMemory;

if (orphans.length === 0) { delete staticData.orphanUncertainty; }

var displayOrphans = alertableOrphans
  .sort(function(a, b) { return b.runningMinutes - a.runningMinutes; })
  .slice(0, 5);
var omittedCount = Math.max(alertableOrphans.length - 5, 0);

var orphanArray = orphans.map(function(o) {
  return { executionId: o.executionId, workflowId: o.workflowId, workflowName: o.workflowName, runningMinutes: o.runningMinutes, orphanCount: orphans.length };
});

var orphanAlertText = '';
if (displayOrphans.length > 0) {
  orphanAlertText = '\u26A0\uFE0F <b>ORPHAN EXECUTION DETECTED</b>\n\n';
  orphanAlertText += displayOrphans.map(function(o) {
    return '<b>Execution:</b> "'' + '\n<b>Workflow:</b> ' + htmlEscape(truncateRaw(o.workflowName, 100)) + '\n<b>Running:</b> ' + o.runningMinutes + ' minutes';
  }).join('\n---\n');
  if (omittedCount > 0) { orphanAlertText += '\n\n\u2026and ' + omittedCount + ' more orphan(s) omitted.'; }
  orphanAlertText += '\n\n<b>Total Orphans:</b> ' + alertableOrphans.length;
  orphanAlertText += '\n<b>Timestamp:</b> ' + new Date().toLocaleString('en-PH', { timeZone: 'Asia/Manila', year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false });
}

return [{
  json: {
    orphanState: orphans.length > 0 ? 'found' : 'none',
    apiError: false,
    hasOrphans: orphans.length > 0,
    hasAlertableOrphans: alertableOrphans.length > 0,
    shouldAlertOrphans: alertableOrphans.length > 0,
    orphanCount: orphans.length,
    alertableOrphanCount: alertableOrphans.length,
    orphanArray: JSON.stringify(orphanArray),
    orphanAlertText: orphanAlertText
  }
}];

const crypto = require('crypto');
const item = $input.first().json || {};
const staticData = $getWorkflowStaticData('global');
var expectedIds = String($env.CRITICAL_WORKFLOW_IDS || '').split(',').map(function(s) { return s.trim(); }).filter(Boolean);
var baseUrl = $env.N8N_BASE_URL || 'http://localhost:5678';

if (expectedIds.length === 0) {
  delete staticData.activationCheckUncertain;
  return [{ json: { activationConfigured: false, activationIssue: false, hasDeactivated: false, activationUncertain: false, shouldAlertActivation: false, deactivatedIds: [], deactivatedUrls: [], activeCount: 0, expectedCount: 0, activationMessage: 'CRITICAL_WORKFLOW_IDS not configured' } }];
}

if (item.error && item.error.message) {
  staticData.activationCheckUncertain = { timestamp: new Date().toISOString(), reason: item.error.message };
  var h1 = crypto.createHash('sha1').update(JSON.stringify({ activationIssue: true, activationUncertain: true, deactivatedIds: [] })).digest('hex');
  var changed1 = h1 !== (staticData.lastActivationAlertHash || '');
  if (changed1) staticData.lastActivationAlertHash = h1;
  return [{ json: { activationConfigured: true, activationIssue: true, hasDeactivated: false, activationUncertain: true, shouldAlertActivation: changed1, deactivatedIds: [], deactivatedUrls: [], activeCount: 0, expectedCount: expectedIds.length, activationMessage: item.error.message } }];
}

var data = item.data || item;
var arr = Array.isArray(data) ? data : (Array.isArray(data.data) ? data.data : []);

if (!Array.isArray(arr)) {
  staticData.activationCheckUncertain = { timestamp: new Date().toISOString(), reason: 'Unexpected response shape' };
  return [{ json: { activationConfigured: true, activationIssue: true, hasDeactivated: false, activationUncertain: true, shouldAlertActivation: false, deactivatedIds: [], deactivatedUrls: [], activeCount: 0, expectedCount: expectedIds.length, activationMessage: 'Unexpected response shape' } }];
}

var activeIds = new Set(arr.map(function(w) { return String(w.id); }));
var deactivatedIds = expectedIds.filter(function(id) { return !activeIds.has(String(id)); });
var deactivatedUrls = deactivatedIds.map(function(id) { return baseUrl + '/workflow/' + id; });

var activationIssue = deactivatedIds.length > 0;
var activationUncertain = false;
var activationMessage = activationIssue ? deactivatedIds.length + ' critical workflow(s) inactive' : 'All critical workflows active';

var stateHash = crypto.createHash('sha1').update(JSON.stringify({ activationIssue: activationIssue, activationUncertain: false, deactivatedIds: deactivatedIds.sort() })).digest('hex');
var lastHash = staticData.lastActivationAlertHash || '';
var activationChanged = stateHash !== lastHash;

if (activationIssue && activationChanged) { staticData.lastActivationAlertHash = stateHash; }

delete staticData.activationCheckUncertain;

return [{ json: { activationConfigured: true, activationIssue: activationIssue, hasDeactivated: deactivatedIds.length > 0, activationUncertain: false, shouldAlertActivation: activationIssue && activationChanged, deactivatedIds: deactivatedIds, deactivatedUrls: deactivatedUrls, activeCount: activeIds.size, expectedCount: expectedIds.length, activationMessage: activationMessage } }];

